 private drawSpellbook(w:number,h:number){if(!this.spellbookOpen||this.state?.phase!=='running')return;const c=mainContext,pw=Math.min(700,w-16),ph=Math.min(520,h-16),x=(w-pw)/2,y=(h-ph)/2,me=this.me();cbox(c,0,0,w,h,'rgba(8,6,12,.48)');cbox(c,x,y,pw,ph,'rgba(18,14,27,.97)');this.text(`法术书 · 特殊组合 ${this.state.discoveredRecipeIds.length}/${RECIPES.length}`,x+18,y+30,18,'#ffe8a8');this.text('特殊组合通过释放发现；携带卷轴立即解锁强化组合',x+18,y+51,11,'#bdb3c9');let row=0,rowH=ph<430?42:48;for(const recipe of RECIPES){if(!this.state.discoveredRecipeIds.includes(recipe.id))continue;const plan=resolveSpell(recipe.pattern)!;const damage=plan.effects.filter(e=>e.type==='damage').reduce((n,e)=>n+e.amount,0),heal=plan.effects.filter(e=>e.type==='heal').reduce((n,e)=>n+e.amount,0),yy=y+78+row*rowH;if(yy>y+ph-20)break;cbox(c,x+12,yy-20,pw-24,rowH-5,row%2?'#272032':'#30263b');this.text(`${plan.name}  ${recipe.pattern.map(e=>labels[e]).join(' → ')}`,x+22,yy-1,13,'#fff');this.text(`${plan.delivery}${damage?` · 伤害 ${damage}`:''}${heal?` · 治疗 ${heal}`:''}${plan.radius?` · 范围 ${Math.round(plan.radius)}`:''}`,x+22,yy+15,10,'#b9d9ff');row++;}for(const scroll of SCROLLS){const count=me?.inventory.filter(item=>isScroll(item)&&item.spellId===scroll.spellId).length??0;if(!count)continue;const yy=y+78+row*rowH;if(yy>y+ph-20)break;cbox(c,x+12,yy-20,pw-24,rowH-5,'#493d26');this.text(`卷轴 · ${scroll.name} ×${count}  ${scroll.pattern.map(e=>labels[e]).join(' → ')}`,x+22,yy-1,13,'#f3d477');this.text(`${scroll.description} · 冷却20秒`,x+22,yy+15,10,'#e6d5a2');row++;}if(!row)this.text('尚未发现特殊配方或携带卷轴。',x+pw/2,y+ph/2,14,'#aaa','center');}
