 private itemStats(item:EquipmentItem){const parts:string[]=[];if(item.stats.spellPower)parts.push(`威力+${Math.round(item.stats.spellPower*100)}%`);if(item.stats.castSpeed)parts.push(`施法+${Math.round(item.stats.castSpeed*100)}%`);if(item.stats.damageReduction)parts.push(`减伤+${Math.round(item.stats.damageReduction*100)}%`);if(item.stats.moveSpeed)parts.push(`移速+${Math.round(item.stats.moveSpeed*100)}%`);return parts.join(' ')||'基础装备';}
 private drawAim(now:number){const state=this.aim;if(state){const origin=this.toScreen(this.local),angle=angleTo(this.local,state.target),color=colors[state.plan.elements[0]!];mainContext.strokeStyle=color;mainContext.fillStyle=`${color}33`;mainContext.lineWidth=3;if(state.plan.delivery==='cone'){mainContext.beginPath();mainContext.moveTo(origin.x,origin.y);mainContext.arc(origin.x,origin.y,state.plan.range*this.view.scale,angle-state.plan.coneAngle/2,angle+state.plan.coneAngle/2);mainContext.closePath();mainContext.fill();mainContext.stroke();}else if(state.plan.delivery==='targeted'||state.plan.delivery==='area'){this.circle(state.target,state.plan.radius,color,false);}else if(state.plan.delivery==='projectile'){const end=this.toScreen(state.target);mainContext.beginPath();mainContext.moveTo(origin.x,origin.y);mainContext.lineTo(end.x,end.y);mainContext.stroke();}else if(state.plan.delivery==='beam'){const end=this.toScreen(this.beamEnd(angle,state.plan.range));mainContext.beginPath();mainContext.moveTo(origin.x,origin.y);mainContext.lineTo(end.x,end.y);mainContext.stroke();const progress=clamp((now-state.startedAt)/state.plan.castMs,0,1);this.text(`吟唱 ${Math.round(progress*100)}%`,origin.x,origin.y-45,13,'#fff','center');}}
  if(this.pending&&(this.pending.plan.delivery==='targeted'||this.pending.plan.delivery==='area')){const pulse=1+Math.sin(now/80)*.05;this.circle(this.pending.target,this.pending.plan.radius*pulse,'#ffcc66',false);}if(this.beam){const power=beamPower(now-this.beam.startedAt),width=this.beam.plan.radius*power,blocked=this.beamEnd(this.beam.angle,this.beam.plan.range),max=distance(this.local,blocked),hits=beamTargets(this.local,this.beam.angle,width,this.enemies(),this.beam.plan.pierce,max),end=hits.length?{x:this.local.x+Math.cos(this.beam.angle)*hits.at(-1)!.along,y:this.local.y+Math.sin(this.beam.angle)*hits.at(-1)!.along}:blocked,a=this.toScreen(this.local),b=this.toScreen(end);mainContext.strokeStyle=colors[this.beam.plan.elements[0]!];mainContext.lineWidth=Math.max(3,width*2*this.view.scale);mainContext.beginPath();mainContext.moveTo(a.x,a.y);mainContext.lineTo(b.x,b.y);mainContext.stroke();}}
 private drawVisual(v:SpellVisual,now:number){const alpha=clamp((v.endsAt-now)/(v.endsAt-v.startedAt),0,1),color=colors[v.color];mainContext.globalAlpha=alpha;if(v.kind==='cone'){const o=this.toScreen(v.origin),half=(v.coneAngle??1.04)/2;mainContext.fillStyle=color;mainContext.beginPath();mainContext.moveTo(o.x,o.y);mainContext.arc(o.x,o.y,v.radius*this.view.scale,v.angle-half,v.angle+half);mainContext.closePath();mainContext.fill();}else if(v.kind==='beam'){const a=this.toScreen(v.origin),b=this.toScreen(v.target);mainContext.strokeStyle=color;mainContext.lineWidth=Math.max(5,v.radius*this.view.scale);mainContext.beginPath();mainContext.moveTo(a.x,a.y);mainContext.lineTo(b.x,b.y);mainContext.stroke();}else if(v.kind==='projectile'){const progress=clamp((now-v.startedAt)/(v.endsAt-v.startedAt),0,1),position={x:v.origin.x+(v.target.x-v.origin.x)*progress,y:v.origin.y+(v.target.y-v.origin.y)*progress};this.circle(position,Math.max(8,v.radius),color,true);}else this.circle(v.target,v.radius,color,true);mainContext.globalAlpha=1;}
 private drawEnemy(e:EnemyState,now:number){const c=mainContext,p=this.toScreen({x:e.x,y:e.y-e.controls.z}),r=e.radius*this.view.scale;c.strokeStyle=now<e.flashUntil?'#fff':e.kind==='water-fiend'?'#54baff':e.kind==='shooter'?'#d298ff':'#ff745f';c.lineWidth=5;c.strokeRect(p.x-r,p.y-r,r*2,r*2);c.fillStyle='#210d16';c.fillRect(p.x-r,p.y-r-11,r*2,6);c.fillStyle='#ff5868';c.fillRect(p.x-r,p.y-r-11,r*2*clamp(e.hp/e.maxHp,0,1),6);this.text(e.kind,p.x,p.y+4,11,'#fff','center');if(e.attack){const wallNow=Date.now(),t=clamp((e.attack.firesAt-wallNow)/(e.attack.firesAt-e.attack.startedAt),0,1);c.strokeStyle='#ffdf65';c.lineWidth=4;c.beginPath();c.arc(p.x,p.y,r+8,-Math.PI/2,-Math.PI/2+(1-t)*Math.PI*2);c.stroke();}this.drawStatuses(e.statuses,p.x,p.y+r+20);}
 private drawPlayer(p:{x:number;y:number;z:number;hp:number;downed:boolean;statuses?:StatusInstance[]},color:string,name:string,activity?:PlayerActivity){const c=mainContext,ground=this.toScreen(p),s=this.toScreen({x:p.x,y:p.y-p.z}),r=25*this.view.scale;c.fillStyle='rgba(0,0,0,.3)';c.beginPath();c.ellipse(ground.x,ground.y+r*.8,r,r*.35,0,0,Math.PI*2);c.fill();c.fillStyle=p.downed?'#555':color;c.fillRect(s.x-r,s.y-r,r*2,r*2);c.strokeStyle='#fff';c.lineWidth=2;c.strokeRect(s.x-r,s.y-r,r*2,r*2);const phase=activity&&activity.phase!=='idle'?` · ${{selecting:'选元素',aiming:'瞄准',windup:'前摇',channeling:'引导',recovery:'后摇',interrupted:'打断',downed:'倒地',stunned:'眩晕',idle:''}[activity.phase]}`:'';this.text(`${name}${phase}`,s.x,s.y-r-12,12,'#fff','center');if(activity?.elements.length)this.text(activity.elements.map(e=>labels[e]).join('+'),s.x,s.y-r-28,10,'#ffe9a8','center');c.fillStyle='#220b13';c.fillRect(s.x-r,s.y+r+5,r*2,5);c.fillStyle='#62e77b';c.fillRect(s.x-r,s.y+r+5,r*2*clamp(p.hp/100,0,1),5);this.drawStatuses(p.statuses??[],s.x,s.y+r+20);}
 private drawStatuses(statuses:StatusInstance[],x:number,y:number){const names:Record<StatusInstance['kind'],string>={wet:'潮湿',burning:'燃烧',chilled:'减速',frozen:'冻结',shocked:'感电',shielded:'护盾','fire-ward':'防火','frost-ward':'防冻','water-ward':'防潮',haste:'加速'};this.text(statuses.map(s=>names[s.kind]).join(' '),x,y,10,'#d9efff','center');}
